// O(n · 2ⁿ) time (we produce 2ⁿ subsets, each up to length n).
// O(n) extra recursion depth.
function subsets(nums) {
  const out = [];
  function go(start, cur) {
    out.push([...cur]);                 // snapshot current subset
    for (let i = start; i < nums.length; i++) {
      cur.push(nums[i]);
      go(i + 1, cur);
      cur.pop();                        // backtrack
    }
  }
  go(0, []);
  return out;
}
